    deeper: `**\u6587\u672C\u6839\u57FA**\uFF1Alucidit\xE9 \u5728\u300A\u897F\u897F\u5F17\u65AF\u795E\u8BDD\u300B\u4E2D\u51FA\u73B0\u591A\u6B21\uFF0C\u4F46\u6700\u91CD\u8981\u7684\u4E00\u6B21\u662F\u5728\u8BA8\u8BBA\u8352\u8BDE\u63A8\u7406\u7684\u7ED3\u8BBA\u65F6\uFF1A\u52A0\u7F2A\u8BF4\u8352\u8BDE\u63A8\u7406\u7684\u7B2C\u4E00\u4E2A\u7ED3\u679C\u662F"\u6E05\u9192"\u3002\u5B83\u662F\u4ECE\u770B\u89C1\u8352\u8BDE\u5230\u5F00\u59CB\u884C\u52A8\u4E4B\u95F4\u7684**\u8FC7\u6E21\u72B6\u6001**\u3002\u6CA1\u6709\u6E05\u9192\uFF0C\u4F60\u770B\u5230\u7684\u8352\u8BDE\u53EA\u662F\u4E00\u95EA\u800C\u8FC7\u7684\u611F\u89C9\uFF1B\u6709\u4E86\u6E05\u9192\uFF0C\u8352\u8BDE\u624D\u53D8\u6210\u4E00\u79CD**\u6301\u7EED\u7684\u8BA4\u77E5**\u3002

**\u9ED8\u5C14\u7D22\u7684\u6E05\u9192**\uFF1A\u300A\u5C40\u5916\u4EBA\u300B\u662F\u6E05\u9192\u6982\u5FF5\u7684\u6587\u5B66\u5316\u5448\u73B0\u3002\u9ED8\u5C14\u7D22\u6700\u5E38\u88AB\u8BEF\u8BFB\u4E3A"\u51B7\u6F20"\u6216"\u53CD\u793E\u4F1A"\u3002\u4F46\u52A0\u7F2A\u5728\u300A\u5C40\u5916\u4EBA\u300B\u7F8E\u56FD\u7248\u5E8F\u8A00\u4E2D\u660E\u786E\u8BF4\uFF1A\u9ED8\u5C14\u7D22\u662F"\u552F\u4E00\u7684\u57FA\u7763"\u2014\u2014\u4E0D\u662F\u56E0\u4E3A\u4ED6\u5723\u6D01\uFF0C\u800C\u662F\u56E0\u4E3A\u4ED6**\u62D2\u7EDD\u8BF4\u8C0E**\u3002\u5728\u4E00\u4E2A\u5EFA\u7ACB\u5728\u793E\u4EA4\u8C0E\u8A00\u4E4B\u4E0A\u7684\u793E\u4F1A\u91CC\uFF0C\u62D2\u7EDD\u8BF4\u8C0E\u672C\u8EAB\u5C31\u662F\u4E00\u79CD\u6781\u7AEF\u7684\u6E05\u9192\u3002

\u9ED8\u5C14\u7D22\u5728\u6BCD\u4EB2\u846C\u793C\u4E0A\u4E0D\u54ED\u2014\u2014\u4E0D\u662F\u56E0\u4E3A\u4E0D\u60B2\u4F24\uFF0C\u800C\u662F\u56E0\u4E3A\u4ED6**\u4E0D\u786E\u5B9A\u81EA\u5DF1\u662F\u4E0D\u662F\u60B2\u4F24**\uFF0C\u4ED6\u62D2\u7EDD\u4E3A\u4E86\u6EE1\u8DB3\u793E\u4F1A\u671F\u5F85\u800C\u6324\u51FA\u4E00\u4E2A\u4E0D\u786E\u5B9A\u7684\u60C5\u7EEA\u3002\u4ED6\u5728\u6CD5\u5EAD\u4E0A\u4E0D\u4E3A\u81EA\u5DF1\u8FA9\u62A4\u2014\u2014\u4E0D\u662F\u56E0\u4E3A\u4E0D\u60F3\u6D3B\uFF0C\u800C\u662F\u56E0\u4E3A\u4ED6**\u4E0D\u613F\u610F\u5047\u88C5\u540E\u6094\u4E00\u4EF6\u4ED6\u65E0\u6CD5\u786E\u8BA4\u81EA\u5DF1\u662F\u5426\u540E\u6094\u7684\u4E8B**\u3002\u8FD9\u79CD\u6E05\u9192\u662F\u6781\u7AEF\u7684\u3001\u5371\u9669\u7684\u2014\u2014\u5B83\u628A\u9ED8\u5C14\u7D22\u9001\u4E0A\u4E86\u65AD\u5934\u53F0\u3002

**\u6E05\u9192\u4E0E"\u6B63\u5348\u601D\u60F3"**\uFF1A\u5728\u52A0\u7F2A\u540E\u671F\u7684\u601D\u60F3\u4E2D\uFF0C\u6E05\u9192\u8FDB\u5316\u4E3A\u4ED6\u6240\u8BF4\u7684"\u6B63\u5348\u601D\u60F3"\uFF08la pens\xE9e de midi\uFF09\uFF0C\u89C1\u300A\u53CD\u6297\u8005\u300B\uFF08L'Homme r\xE9volt\xE9, 1951\uFF09\u6700\u540E\u4E00\u7AE0\u3002\u6B63\u5348\u662F\u5149\u7EBF\u6700\u5F3A\u7684\u65F6\u523B\u2014\u2014\u6CA1\u6709\u9634\u5F71\uFF0C\u4E00\u5207\u88AB\u7167\u4EAE\u3002\u52A0\u7F2A\u7684\u6B63\u5348\u601D\u60F3\u662F\u53CD\u5BF9\u4E00\u5207\u6781\u7AEF\u2014\u2014\u4E0D\u662F\u6E29\u541E\u7684"\u4E2D\u5EB8"\uFF0C\u800C\u662F\u5728\u4E24\u4E2A\u6781\u7AEF\u4E4B\u95F4\u4FDD\u6301**\u6700\u9AD8\u5F3A\u5EA6\u7684\u6E05\u9192**\u3002\u4ED6\u6279\u8BC4\u9769\u547D\u8D70\u5411\u66B4\u653F\uFF08\u4ECE\u53CD\u6297\u6ED1\u5411\u6740\u622E\uFF09\uFF0C\u4E5F\u6279\u8BC4\u865A\u65E0\u4E3B\u4E49\u8D70\u5411\u51B7\u6F20\uFF08\u4ECE\u770B\u89C1\u8352\u8BDE\u6ED1\u5411\u4EC0\u4E48\u90FD\u4E0D\u505A\uFF09\u3002\u6E05\u9192\u662F\u8FD9\u4E24\u4E2A\u6DF1\u6E0A\u4E4B\u95F4\u7684\u7A84\u8DEF\u3002

**\u52A0\u7F2A\u4E0E\u6885\u6D1B-\u5E9E\u8482**\uFF1A\u6885\u6D1B-\u5E9E\u8482\uFF08Merleau-Ponty\uFF09\u5728\u300A\u4EBA\u9053\u4E3B\u4E49\u4E0E\u6050\u6016\u300B\u4E2D\u6279\u8BC4\u52A0\u7F2A\u7684\u6E05\u9192\u662F\u4E00\u79CD"\u7F8E\u4E3D\u7075\u9B42"\u2014\u2014\u770B\u89C1\u4E86\u95EE\u9898\u4F46\u62D2\u7EDD\u5F04\u810F\u624B\u3002\u52A0\u7F2A\u7684\u56DE\u5E94\u662F\uFF1A\u5F04\u810F\u624B\u4E0D\u662F\u52C7\u6C14\uFF0C\u662F\u653E\u5F03\u3002\u771F\u6B63\u7684\u56F0\u96BE\u4E0D\u662F"\u4E3A\u4E86\u76EE\u7684\u4E0D\u62E9\u624B\u6BB5"\u2014\u2014\u90A3\u5F88\u5BB9\u6613\u2014\u2014\u800C\u662F"\u5728\u624B\u6BB5\u53D7\u9650\u7684\u60C5\u51B5\u4E0B\u4ECD\u7136\u884C\u52A8"\u3002\u4F55\u519B\u7684\u65B9\u5F0F\u5370\u8BC1\u4E86\u8FD9\u4E00\u70B9\uFF1A\u4ED6\u7684\u884C\u52A8\u7A7A\u95F4\u6781\u5C0F\uFF08\u53EA\u662F\u5F00\u8F66\uFF09\uFF0C\u4F46\u4ED6\u7684\u6E05\u9192\u5728\u90A3\u4E2A\u6781\u5C0F\u7684\u7A7A\u95F4\u91CC\u5B8C\u5168\u5C55\u5F00\u3002

**\u6E05\u9192\u7684\u6096\u8BBA**\uFF1A\u52A0\u7F2A\u81EA\u5DF1\u627F\u8BA4\u6E05\u9192\u6709\u4E00\u4E2A\u6096\u8BBA\u2014\u2014\u5B83\u53EF\u80FD\u5BFC\u81F4\u762B\u75EA\u3002\u5982\u679C\u4F60\u770B\u5F97\u592A\u6E05\u695A\u3001\u592A\u5F7B\u5E95\uFF0C\u4F60\u53EF\u80FD\u65E0\u6CD5\u884C\u52A8\u3002\u6240\u6709\u884C\u52A8\u90FD\u9700\u8981\u67D0\u79CD\u7A0B\u5EA6\u7684"\u9057\u5FD8"\u6216"\u5FFD\u7565"\u2014\u2014\u4F60\u4E0D\u53EF\u80FD\u6BCF\u4E00\u79D2\u90FD\u60F3\u7740"\u8FD9\u6CA1\u6709\u610F\u4E49"\u8FD8\u80FD\u505A\u4E8B\u3002\u52A0\u7F2A\u7684\u89E3\u51B3\u65B9\u5F0F\u662F\uFF1A\u6E05\u9192\u4E0D\u662F\u4E00\u4E2A24\u5C0F\u65F6\u4E0D\u95F4\u65AD\u7684\u72B6\u6001\uFF0C\u800C\u662F\u4E00\u79CD**\u5E95\u5C42\u80FD\u529B**\u3002\u5B83\u662F\u4F60\u80FD\u968F\u65F6\u8C03\u7528\u7684\u89C6\u89D2\u2014\u2014\u50CF\u4F55\u519B\u4E00\u6837\uFF0C\u4F60\u53EF\u4EE5\u5728\u51CC\u6668\u4E09\u70B9\u770B\u89C1\u4E00\u5207\uFF0C\u7136\u540E\u65E9\u4E0A\u516D\u70B9\u56DE\u5BB6\u7761\u89C9\u3002\u6E05\u9192\u4E0D\u8981\u6C42\u4F60\u6C38\u8FDC\u4E0D\u95ED\u773C\u2014\u2014\u5B83\u8981\u6C42\u4F60**\u80FD\u7741\u773C\u7684\u65F6\u5019\u4E0D\u9A97\u81EA\u5DF1**\u3002

**\u4E1C\u65B9\u53C2\u7167**\uFF1A\u6E05\u9192\u6982\u5FF5\u548C\u7985\u5B97\u7684"\u89C9"\u6709\u8868\u9762\u76F8\u4F3C\u2014\u2014\u90FD\u5F3A\u8C03"\u770B"\u672C\u8EAB\u7684\u529B\u91CF\uFF0C\u90FD\u8B66\u60D5\u6982\u5FF5\u5316\u7684\u906E\u853D\u3002\u4F46\u533A\u522B\u5728\u4E8E\uFF1A\u7985\u5B97\u7684\u89C9\u6307\u5411\u4E00\u79CD\u8D85\u8D8A\u4E3B\u5BA2\u4E8C\u5206\u7684\u72B6\u6001\uFF08"\u80FD\u6240\u53CC\u4EA1"\uFF09\uFF0C\u800C\u52A0\u7F2A\u7684\u6E05\u9192\u6070\u6070\u5EFA\u7ACB\u5728\u4E3B\u5BA2\u4E8C\u5206\u4E4B\u4E0A\u2014\u2014**\u6211**\u6E05\u9192\u5730\u770B\u7740**\u4E16\u754C**\uFF0C\u88C2\u7F1D\u59CB\u7EC8\u5B58\u5728\u3002\u7985\u5B97\u8981\u6D88\u89E3\u770B\u8005\u548C\u88AB\u770B\u8005\u7684\u533A\u5206\uFF1B\u52A0\u7F2A\u8981\u5728\u533A\u5206\u4E2D\u7AD9\u7A33\u3002

**\u4F55\u519B\u4F5C\u4E3A\u6E05\u9192\u7684\u5316\u8EAB**\uFF1A\u4F55\u519B\u4E0D\u662F\u54F2\u5B66\u5BB6\uFF0C\u4ED6\u4E0D\u4F1A\u7528"\u8352\u8BDE"\u548C"\u6E05\u9192"\u8FD9\u4E9B\u8BCD\u3002\u4F46\u4ED6\u7684\u5B58\u5728\u65B9\u5F0F\u5C31\u662F\u52A0\u7F2A\u8BF4\u7684\u90A3\u79CD\u4E1C\u897F\uFF1A\u4ED6\u6BCF\u5929\u591C\u91CC\u7A7F\u8FC7\u57CE\u5E02\u7684\u9ED1\u6697\uFF0C\u770B\u89C1\u5404\u79CD\u5F62\u72B6\u7684\u82E6\u96BE\u548C\u8352\u8BDE\u2014\u2014\u4F46\u4ED6\u6CA1\u6709\u88AB\u4EFB\u4F55\u4E00\u79CD\u541E\u6389\u3002\u4ED6\u7684\u65B9\u5F0F\u6781\u5EA6\u6734\u7D20\uFF1A"\u6211\u628A\u4F60\u5B89\u5168\u9001\u5230\u3002" \u8FD9\u53E5\u8BDD\u91CC\u6709\u52A0\u7F2A\u5168\u90E8\u7684\u6E05\u9192\u4F26\u7406\u2014\u2014\u6211\u4E0D\u5047\u88C5\u80FD\u62EF\u6551\u4F60\uFF0C\u6211\u4E0D\u5047\u88C5\u7406\u89E3\u4F60\uFF0C\u4F46\u6211\u80FD\u505A\u5230\u7684\u90A3\u4EF6\u5C0F\u4E8B\uFF0C\u6211\u505A\u5230\u4E86\u3002`,
    links: {
      pre: ["\u8352\u8BDE", "\u54F2\u5B66\u81EA\u6740"],
      post: ["\u53CD\u6297", "\u897F\u897F\u5F17\u65AF"]
    }
